// ============================================================================
// DIVERGENCE 4: var on empty tensor.
//
// Upstream: `torch.var(torch.tensor([]))` returns NaN (a scalar warning is
// printed about correction<=0, but the value comes back as `nan` from the
// `0/0` path). Source: aten/src/ATen/native/ReduceOps.cpp:1858 (the
// `std::max(0.0, self.numel() - correction)` clamp + IEEE-754 0/0=nan).
// ferrotorch (reduction.rs:1680-1683): explicitly returns
// `FerrotorchError::InvalidArgument { message: "var: cannot reduce empty tensor" }`.
//
// This is an API-level divergence: torch returns a NaN scalar Tensor; ferrotorch
// raises an error. A caller `torch_to_ferrotorch_translation_X(x)` that
// uses var(empty) gets an Err in Rust where torch gives a NaN tensor.
// ============================================================================

#[test]
fn divergence_var_empty_returns_nan_not_error() {
    // From live oracle:
    //   torch.var(torch.tensor([], dtype=torch.float64)).item() is nan
    //
    // ferrotorch raises InvalidArgument instead of returning a NaN scalar.
    let x = leaf(&[], &[0], false);
    let result = red_var(&x, true);
    match result {
        Ok(t) => {
            let v = t.item().expect("item");
            assert!(
                v.is_nan(),
                "torch.var(empty) returns NaN scalar; ferrotorch returned {v}"
            );
        }
        Err(e) => panic!(
            "torch.var(empty) returns NaN scalar (no error); ferrotorch \
             raised {e:?}. Should return a tensor holding NaN to match upstream."
        ),
    }
}

#[test]
fn divergence_std_empty_returns_nan_not_error() {
    // From live oracle:
    //   torch.std(torch.tensor([], dtype=torch.float64)).item() is nan
    let x = leaf(&[], &[0], false);
    let result = red_std(&x, true);
    match result {
        Ok(t) => {
            let v = t.item().expect("item");
            assert!(
                v.is_nan(),
                "torch.std(empty) returns NaN scalar; ferrotorch returned {v}"
            );
        }
        Err(e) => panic!(
            "torch.std(empty) returns NaN scalar (no error); ferrotorch \
             raised {e:?}."
        ),
    }
}

// ============================================================================
// DIVERGENCE 5: argmax with NaN as data[0] — the "trivial first element is
// NaN" case happens to MATCH upstream by coincidence (best_idx=0 stays at
// 0 since every comparison is false). Document as observation to prevent
// regression.
// ============================================================================

#[test]
fn observation_argmax_nan_at_zero_happens_to_match_torch() {
    // From live oracle:
    //   torch.argmax(torch.tensor([nan, 1.0, 3.0])).item() == 0
    //
    // ferrotorch: best_val starts as NaN; every later v > NaN is false,
    // so best_idx stays 0. Coincidental match. Document — if this code
    // changes (e.g. someone "fixes" the NaN-skipping to skip the FIRST
    // NaN too), this test should fail.
    let x = leaf(&[f64::NAN, 1.0, 3.0], &[3], false);
    let result = argmax(&x).expect("argmax forward");
    let r = result.data().expect("data");
    assert_eq!(r, &[0i64]);
}
